#!/usr/bin/env bash
# negotiate-with-procurement.sh — Negotiate with procurement（与采购对线 / 谈判） SOP walkthrough for B2B 大客户销售.
# Auto-generated by cli_writer.py. Source: research/03-workflows.md.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="B2B 大客户销售"
WORKFLOW="Negotiate with procurement（与采购对线 / 谈判）"

usage() {
  cat <<EOF
negotiate-with-procurement.sh — Walk through "${WORKFLOW}" SOP for ${INDUSTRY}

逐步走完这个工作流的入门 SOP, 然后做失败模式自检, 输出走查报告。

USAGE:
  ./negotiate-with-procurement.sh             # interactive
  ./negotiate-with-procurement.sh --dry-run
  ./negotiate-with-procurement.sh --json
  ./negotiate-with-procurement.sh --explain
  ./negotiate-with-procurement.sh --help
EOF
}

explain() {
  cat <<'EOT'
这个 SOP 走查脚本帮你完成 "Negotiate with procurement（与采购对线 / 谈判）" 工作流。

一句话: When the champion's done and the deal hits procurement/legal, protect margin by **trading concessions** (not discounting) — treating negotiation as a process you ran all along, not a price event at the end. (evidence: [T03-S023, T03-S025])

入门 SOP 共 4 步, 失败模式自检 4 项。

相关心智模型:
  • 问 ⇄ 教 ⇄ 筛:三派第一性张力,资深人按层混用: 复杂销售的方法论分三派——诊断式提问(SPIN/Gap:「客户有答案,问到痛点不可否认为止」)⇄ 挑战式教学(Challenger:「客户对自己问题的认知是错的,用商业洞见 reframe」)⇄ 资格
  • 头号对手是「不决策」,不是竞品: 预测内丢单的最大去向不是输给对手,而是客户「什么都不做」——维持现状;且一旦购买意向形成,买方更怕「搞砸」(FOMU)而非「错过」(FOMO),所以晚期停滞要按「犹豫」处理(去风险),不是按「异议」处

来源: research/03-workflows.md.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a SOP_STEPS=(
  "**Establish value before price** — by the time you reach procurement, the business value/ROI should already be agreed (negotiation is the *extension* of a process, not its start). (evidence: [T03-S023])"
  "**Decode procurement's real drivers** — uncover the business + personal interests behind their requirements (hit a budget number? show a saving? de-risk the vendor?). (evidence: [T03-S023])"
  "**Build a give/get playlist** — predefine what you can trade and what you want in return (anchors + multiple options): discount ⇄ longer term / prepay / reference / case study / expansion / faster signature. (evidence: [T03-S023, T03-S025])"
  "**Trade, never just discount** — every concession is contingent (\"if you can do X, I can do Y\"); use calibrated questions / tactical empathy to keep it collaborative. (evidence: [T03-S023, T03-S024])"
)
declare -a FAILURE_MODES=(
  "**Caving on price to \"save the deal\"**: unilateral discounts train the buyer to keep pushing and admit your price was soft. Avoid: every concession is contingent — trade, don't give. (evidence: [T03-S025])"
  "**Treating negotiation as a final event**: if you didn't build value all along, procurement anchors on price. Avoid: negotiate/validate value from the start of the deal. (evidence: [T03-S023])"
  "**Negotiating against procurement as the decision-maker**: procurement can usually only say no; the EB owns yes. Avoid: re-engage the EB/champion when procurement stalls on terms. (evidence: [T03-S023])"
  "**No give/get playlist ready → concede the wrong things under pressure**: improvising mid-negotiation loses margin. Avoid: predefine tradeable gives + the gets you want (term/prepay/reference/expansion). (evidence: [T03-S023])"
)
declare -a STEP_STATUS=()
declare -a STEP_NOTES=()
declare -a FAIL_CHECK=()

ms_section "${INDUSTRY} · ${WORKFLOW} 走查"
ms_info "逐步走完 ${#SOP_STEPS[@]} 步入门 SOP。每步可标 done / skipped / blocked。"
echo

for i in "${!SOP_STEPS[@]}"; do
  ms_section "Step $((i+1))/${#SOP_STEPS[@]}: ${SOP_STEPS[$i]}"
  ms_prompt "状态? [d=done / s=skipped / b=blocked]"
  read -r status
  STEP_STATUS+=("${status:-d}")
  case "${status:-d}" in
    s) ms_prompt "跳过原因 (一句话):"; read -r note ;;
    b) ms_prompt "blocker (一句话):"; read -r note ;;
    *) note="" ;;
  esac
  STEP_NOTES+=("$note")
done

if [[ ${#FAILURE_MODES[@]} -gt 0 ]]; then
  ms_section "失败模式自检"
  for fm in "${FAILURE_MODES[@]}"; do
    if ms_confirm "你是否避免了 — '$fm' ?"; then
      FAIL_CHECK+=("✓ $fm")
    else
      FAIL_CHECK+=("✗ $fm")
    fi
  done
fi

ms_buffer_append "# ${INDUSTRY} — ${WORKFLOW} 走查报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## SOP 步骤"
ms_buffer_append ""
for i in "${!SOP_STEPS[@]}"; do
  status_icon="?"
  case "${STEP_STATUS[$i]}" in
    d|D) status_icon="✓" ;;
    s|S) status_icon="↷" ;;
    b|B) status_icon="✗" ;;
  esac
  if [[ -n "${STEP_NOTES[$i]}" ]]; then
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]} — ${STEP_NOTES[$i]}"
  else
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]}"
  fi
done
ms_buffer_append ""
if [[ ${#FAIL_CHECK[@]} -gt 0 ]]; then
  ms_buffer_append "## 失败模式自检"
  ms_buffer_append ""
  for line in "${FAIL_CHECK[@]}"; do
    ms_buffer_append "- $line"
  done
  ms_buffer_append ""
fi

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "workflow" "${WORKFLOW}" \
    "step_count" "${#SOP_STEPS[@]}" \
    "failure_check_count" "${#FAILURE_MODES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "negotiate-with-procurement-walkthrough"
fi
